{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://landinghub.local/schemas/validator-result.schema.json",
  "title": "Validator Result",
  "description": "Structured Validator-A/B result consumed by 02-HARNESS automation.",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "task_id",
    "agent",
    "tool",
    "tier",
    "verdict",
    "criteria_results",
    "errors",
    "github_commit",
    "tier_reclassification_needed",
    "tier_reclassification_reason",
    "log"
  ],
  "properties": {
    "task_id": {
      "type": "string",
      "pattern": "^TASK-[0-9]{8}-[0-9]{3}$"
    },
    "agent": {
      "enum": ["Validator-A", "Validator-B"]
    },
    "tool": {
      "enum": ["Codex CLI", "Gemini CLI"]
    },
    "tier": {
      "enum": ["Tier2", "Tier3"]
    },
    "verdict": {
      "enum": ["PASS", "FAIL"]
    },
    "criteria_results": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["criterion", "result", "detail"],
        "properties": {
          "criterion": {
            "type": "string"
          },
          "result": {
            "enum": ["PASS", "FAIL"]
          },
          "detail": {
            "type": "string"
          }
        }
      }
    },
    "errors": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "severity",
          "evidence_type",
          "location",
          "description",
          "suggestion",
          "evidence"
        ],
        "properties": {
          "severity": {
            "enum": ["CRITICAL", "HIGH", "MEDIUM", "LOW"]
          },
          "evidence_type": {
            "enum": [
              "EXECUTION_PROVEN",
              "STATIC_PROVEN",
              "SPEC_MISMATCH",
              "INFERRED_RISK",
              "SPEC_INTERPRETATION"
            ]
          },
          "location": {
            "type": "string"
          },
          "description": {
            "type": "string"
          },
          "suggestion": {
            "type": "string"
          },
          "evidence": {
            "type": "string"
          }
        }
      }
    },
    "github_commit": {
      "type": ["string", "null"]
    },
    "tier_reclassification_needed": {
      "type": "boolean"
    },
    "tier_reclassification_reason": {
      "type": ["string", "null"]
    },
    "log": {
      "type": "array",
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": ["timestamp", "action", "result"],
        "properties": {
          "timestamp": {
            "type": "string"
          },
          "action": {
            "type": "string"
          },
          "result": {
            "type": "string"
          }
        }
      }
    }
  }
}

