    pattern: /["']?\b(?:api[_-]?key|secret|token)\b["']?\s*[:=]\s*["']?[^"'\s]{8,}/i,
  },
  {
    name: 'aws_access_key_id',
    pattern: /\bAKIA[0-9A-Z]{16}\b/,
  },
